# MetaBlooms Kernel Module: RIDIE Persistence Adapter
# Purpose: Make RIDIE improvements durable without mutating canonical artifacts silently.
#
# Design:
# - RIDIE emits "mutations" (proposed rule/process adjustments) as data.
# - This adapter:
#   1) writes proposals to ridie/proposals.ndjson (append-only)
#   2) writes a checkpoint ridie/state.json (current thresholds + last stage)
#   3) emits ledger events via kernel ledger writer (when available)
# - Promotion is explicit: proposals are only applied when a gate approves them.

from __future__ import annotations
import json
from dataclasses import dataclass
from pathlib import Path
from typing import Any, Dict, List, Optional

@dataclass
class RIDIEPersistence:
    root: Path

    def __post_init__(self):
        (self.root / "ridie").mkdir(parents=True, exist_ok=True)

    @property
    def proposals_path(self) -> Path:
        return self.root / "ridie" / "proposals.ndjson"

    @property
    def state_path(self) -> Path:
        return self.root / "ridie" / "state.json"

    def append_proposals(self, proposals: List[Dict[str, Any]]) -> None:
        if not proposals:
            return
        with self.proposals_path.open("a", encoding="utf-8") as f:
            for p in proposals:
                f.write(json.dumps(p, ensure_ascii=False) + "\n")

    def write_state(self, state: Dict[str, Any]) -> None:
        self.state_path.write_text(json.dumps(state, indent=2, ensure_ascii=False), encoding="utf-8")

    def load_state(self) -> Optional[Dict[str, Any]]:
        if not self.state_path.exists():
            return None
        return json.loads(self.state_path.read_text(encoding="utf-8"))

# RIDIE PERSISTENCE (auto)
try:
    from modules.ridie_persistence import RIDIEPersistence
    _ridie_persist = RIDIEPersistence(root=Path(__file__).resolve().parents[1])
    # if stage context has ridie_mutations, persist them
    if isinstance(stage_result, dict):
        muts = stage_result.get("ridie_mutations") or []
        st = stage_result.get("ridie_state") or {}
        _ridie_persist.append_proposals(muts)
        if st:
            _ridie_persist.write_state(st)
except Exception as _e:
    # Fail-closed policy: persistence failure must surface upstream
    raise
